// --- Color Bottles Data ---
const BOTTLES = [
	{ name: "Crimson", color: "#DC143C" },
	{ name: "Tomato", color: "#FF6347" },
	{ name: "Orange", color: "#FF8C00" },
	{ name: "Gold", color: "#FFD700" },
	{ name: "Chartreuse", color: "#7FFF00" },
	{ name: "Emerald", color: "#50C878" },
	{ name: "Teal", color: "#008080" },
	{ name: "Cyan", color: "#00E5FF" },
	{ name: "Dodger Blue", color: "#1E90FF" },
	{ name: "Indigo", color: "#4B0082" },
	{ name: "Violet", color: "#8A2BE2" },
	{ name: "Magenta", color: "#FF00FF" },
	{ name: "Hot Pink", color: "#FF69B4" },
	{ name: "Coral", color: "#FF7F50" },
	{ name: "Lavender", color: "#B57EDC" },
	{ name: "White", color: "#FFFFFF" }
];

// --- Garnish Emojis ---
const GARNISHES = ["🍊", "🍋", "🍒", "🫒", "🍓", "🌿", "🍍", "🧊", "☂️", "⭐"];

// --- State ---
const state = {
	slot1Color: null,
	slot2Color: null,
	slot1Name: null,
	slot2Name: null,
	activeSlot: 1,
	proportion: 50,
	colorSpace: "srgb",
	recentMixes: []
};

// --- DOM Refs ---
const $ = (sel) => document.querySelector(sel);
const $$ = (sel) => document.querySelectorAll(sel);

const dom = {
	bottleRack: $("#bottle-rack"),
	slot1Glass: $("#slot1-glass"),
	slot1Liquid: $("#slot1-liquid"),
	slot1Name: $("#slot1-name"),
	slot1Picker: $("#slot1-picker"),
	slot2Glass: $("#slot2-glass"),
	slot2Liquid: $("#slot2-liquid"),
	slot2Name: $("#slot2-name"),
	slot2Picker: $("#slot2-picker"),
	proportionSlider: $("#proportion-slider"),
	proportionLeft: $("#proportion-left"),
	proportionRight: $("#proportion-right"),
	colorspaceOptions: $("#colorspace-options"),
	mixBtn: $("#mix-btn"),
	resultLiquid: $("#result-liquid"),
	resultBubbles: $("#result-bubbles"),
	resultSwatch: $("#result-swatch"),
	resultHex: $("#result-hex"),
	resultCode: $("#result-code"),
	copyBtn: $("#copy-btn"),
	copiedToast: $("#copied-toast"),
	resultGradient: $("#result-gradient"),
	gradientCode: $("#gradient-code"),
	gradientWrap: $("#gradient-wrap"),
	galleryGrid: $("#gallery-grid"),
	garnish: $("#garnish"),
	shakerOverlay: $("#shaker-overlay"),
	shakerLiquid: $("#shaker-liquid"),
	shakerParticles: $("#shaker-particles"),
	resultSection: $("#result"),
	glassWrap: $("#result-glass-wrap")
};

// ============================================
// BOTTLE RENDERING
// ============================================

function createBottle(data, index) {
	const bottle = document.createElement("div");
	bottle.className = "bottle no-select";
	bottle.style.setProperty("--bottle-color", data.color);
	bottle.dataset.color = data.color;
	bottle.dataset.name = data.name;
	bottle.dataset.index = index;
	bottle.title = `${data.name} — Click to pour`;

	bottle.innerHTML = `
    <div class="bottle__glow"></div>
    <div class="bottle__cap"></div>
    <div class="bottle__neck"></div>
    <div class="bottle__body">
      <div class="bottle__liquid" style="background: ${data.color};"></div>
      <div class="bottle__shine"></div>
    </div>
    <div class="bottle__label">${data.name}</div>
  `;

	bottle.addEventListener("click", () =>
		pourBottle(data.color, data.name, bottle)
	);
	return bottle;
}

function renderBottles() {
	BOTTLES.forEach((b, i) => {
		dom.bottleRack.appendChild(createBottle(b, i));
	});
}

// ============================================
// POUR LOGIC
// ============================================

function pourBottle(color, name, bottleEl) {
	// Deselect all bottles first
	$$(".bottle--selected").forEach((b) => b.classList.remove("bottle--selected"));

	// Select this bottle
	bottleEl.classList.add("bottle--selected");

	if (state.activeSlot === 1) {
		setSlotColor(1, color, name);
		state.activeSlot = 2;
	} else {
		setSlotColor(2, color, name);
		state.activeSlot = 1;
	}
}

function setSlotColor(slot, color, name) {
	const glass = slot === 1 ? dom.slot1Glass : dom.slot2Glass;
	const liquid = slot === 1 ? dom.slot1Liquid : dom.slot2Liquid;
	const nameEl = slot === 1 ? dom.slot1Name : dom.slot2Name;
	const picker = slot === 1 ? dom.slot1Picker : dom.slot2Picker;

	if (slot === 1) {
		state.slot1Color = color;
		state.slot1Name = name;
	} else {
		state.slot2Color = color;
		state.slot2Name = name;
	}

	// Animate glass
	glass.classList.add("pour-slot__glass--filled", "pour-slot__glass--pouring");
	setTimeout(() => glass.classList.remove("pour-slot__glass--pouring"), 600);

	// Set liquid
	liquid.style.background = color;
	liquid.classList.add("pour-slot__liquid--visible");

	// Update name and picker
	nameEl.textContent = name || color;
	picker.value = color;

	// Update ambient glow on glass
	glass.style.boxShadow = `0 0 25px ${color}40, inset 0 0 20px ${color}20`;
}

// ============================================
// PROPORTION SLIDER
// ============================================

dom.proportionSlider.addEventListener("input", (e) => {
	state.proportion = parseInt(e.target.value);
	dom.proportionLeft.textContent = `${state.proportion}%`;
	dom.proportionRight.textContent = `${100 - state.proportion}%`;
});

// ============================================
// COLOR PICKERS
// ============================================

dom.slot1Picker.addEventListener("input", (e) => {
	setSlotColor(1, e.target.value, e.target.value);
});

dom.slot2Picker.addEventListener("input", (e) => {
	setSlotColor(2, e.target.value, e.target.value);
});

// ============================================
// CLICK ON GLASS TO SELECT SLOT
// ============================================

$("#slot1").addEventListener("click", (e) => {
	if (e.target.closest(".pour-slot__picker")) return;
	state.activeSlot = 1;
	highlightActiveSlot();
});

$("#slot2").addEventListener("click", (e) => {
	if (e.target.closest(".pour-slot__picker")) return;
	state.activeSlot = 2;
	highlightActiveSlot();
});

function highlightActiveSlot() {
	$("#slot1").querySelector(".pour-slot__label").style.color =
		state.activeSlot === 1 ? "var(--accent-3)" : "var(--text-secondary)";
	$("#slot2").querySelector(".pour-slot__label").style.color =
		state.activeSlot === 2 ? "var(--accent-3)" : "var(--text-secondary)";
}

// ============================================
// COLOR SPACE SELECTOR
// ============================================

dom.colorspaceOptions.addEventListener("click", (e) => {
	const btn = e.target.closest(".colorspace__btn");
	if (!btn) return;

	$$(".colorspace__btn").forEach((b) =>
		b.classList.remove("colorspace__btn--active")
	);
	btn.classList.add("colorspace__btn--active");
	state.colorSpace = btn.dataset.space;
});

// ============================================
// MIX BUTTON
// ============================================

dom.mixBtn.addEventListener("click", () => {
	if (!state.slot1Color || !state.slot2Color) {
		shakeElement(dom.mixBtn);
		return;
	}
	performMix();
});

function shakeElement(el) {
	el.style.animation = "none";
	el.offsetHeight; // trigger reflow
	el.style.animation = "shakerShake 0.3s ease 2";
	setTimeout(() => {
		el.style.animation = "";
	}, 700);
}

// ============================================
// PERFORM MIX
// ============================================

async function performMix() {
	const { slot1Color, slot2Color, proportion, colorSpace } = state;

	// Show shaker overlay
	showShaker(slot1Color, slot2Color);

	// Wait for shaker animation
	await delay(1800);

	// Generate CSS color-mix code
	const cssCode = `color-mix(in ${colorSpace}, ${slot1Color} ${proportion}%, ${slot2Color} ${
		100 - proportion
	}%)`;

	// Compute the actual mixed color
	const mixedColor = computeColorMix(
		slot1Color,
		slot2Color,
		proportion,
		colorSpace
	);
	const mixedHex = mixedColor;

	// Hide shaker
	hideShaker();

	// Wait a beat
	await delay(300);

	// Reveal result
	revealResult(mixedHex, cssCode, slot1Color, slot2Color);

	// Add to gallery
	addToGallery(mixedHex, cssCode);
}

// ============================================
// SHAKER ANIMATION
// ============================================

function showShaker(c1, c2) {
	// Mix shaker liquid color visually
	dom.shakerLiquid.style.background = `linear-gradient(180deg, ${c1}, ${c2})`;
	dom.shakerOverlay.classList.add("shaker-overlay--active");

	// Spawn particles
	spawnShakerParticles(c1, c2);
}

function hideShaker() {
	dom.shakerOverlay.classList.remove("shaker-overlay--active");
	dom.shakerParticles.innerHTML = "";
}

function spawnShakerParticles(c1, c2) {
	dom.shakerParticles.innerHTML = "";
	const colors = [c1, c2];
	for (let i = 0; i < 20; i++) {
		const p = document.createElement("div");
		p.className = "shaker-particle";
		p.style.background = colors[Math.floor(Math.random() * 2)];
		p.style.left = `${40 + Math.random() * 20}%`;
		p.style.top = `${40 + Math.random() * 20}%`;
		p.style.width = `${4 + Math.random() * 8}px`;
		p.style.height = p.style.width;
		p.style.setProperty("--tx", `${(Math.random() - 0.5) * 200}px`);
		p.style.setProperty("--ty", `${(Math.random() - 0.5) * 200}px`);
		p.style.animationDelay = `${0.5 + Math.random() * 1}s`;
		dom.shakerParticles.appendChild(p);
	}
}

// ============================================
// COMPUTE COLOR MIX
// ============================================

function computeColorMix(c1, c2, percent, space) {
	// Use an off-screen element with color-mix() to compute the actual color
	// IMPORTANT: don't use display:none — browsers skip computing styles for hidden elements
	const el = document.createElement("div");
	el.style.position = "absolute";
	el.style.top = "-9999px";
	el.style.left = "-9999px";
	el.style.width = "1px";
	el.style.height = "1px";
	el.style.visibility = "hidden";

	const mixExpr = `color-mix(in ${space}, ${c1} ${percent}%, ${c2} ${
		100 - percent
	}%)`;
	el.style.backgroundColor = mixExpr;
	document.body.appendChild(el);

	const computed = getComputedStyle(el).backgroundColor;
	document.body.removeChild(el);

	// If the browser couldn't compute color-mix, fall back to manual interpolation
	const hex = rgbStringToHex(computed);
	if (hex === "#000000" && c1 !== "#000000" && c2 !== "#000000") {
		return manualColorMix(c1, c2, percent / 100);
	}
	return hex;
}

function rgbStringToHex(colorStr) {
	if (!colorStr || colorStr === "transparent" || colorStr === "rgba(0, 0, 0, 0)")
		return "#000000";

	// Try rgb/rgba with commas: rgb(128, 0, 255) or rgba(128, 0, 255, 1)
	let match = colorStr.match(/rgba?\(\s*([\d.]+)\s*,\s*([\d.]+)\s*,\s*([\d.]+)/);
	if (match) {
		return toHex(
			Math.round(parseFloat(match[1])),
			Math.round(parseFloat(match[2])),
			Math.round(parseFloat(match[3]))
		);
	}

	// Try rgb/rgba without commas (modern syntax): rgb(128 0 255) or rgb(128 0 255 / 1)
	match = colorStr.match(/rgba?\(\s*([\d.]+)\s+([\d.]+)\s+([\d.]+)/);
	if (match) {
		return toHex(
			Math.round(parseFloat(match[1])),
			Math.round(parseFloat(match[2])),
			Math.round(parseFloat(match[3]))
		);
	}

	// Try color() function: color(srgb 0.5 0.3 0.8) — values are 0-1
	match = colorStr.match(/color\(\s*[\w-]+\s+([\d.]+)\s+([\d.]+)\s+([\d.]+)/);
	if (match) {
		return toHex(
			Math.round(clamp01(parseFloat(match[1])) * 255),
			Math.round(clamp01(parseFloat(match[2])) * 255),
			Math.round(clamp01(parseFloat(match[3])) * 255)
		);
	}

	// Try oklch/lch/lab — the browser should still resolve to rgb, but just in case
	// fall back to manual black
	return "#000000";
}

function toHex(r, g, b) {
	r = Math.max(0, Math.min(255, r));
	g = Math.max(0, Math.min(255, g));
	b = Math.max(0, Math.min(255, b));
	return `#${((1 << 24) + (r << 16) + (g << 8) + b)
		.toString(16)
		.slice(1)
		.toUpperCase()}`;
}

function clamp01(v) {
	return Math.max(0, Math.min(1, v));
}

// Manual fallback for browsers that don't support color-mix()
function manualColorMix(hex1, hex2, t) {
	const r1 = parseInt(hex1.slice(1, 3), 16);
	const g1 = parseInt(hex1.slice(3, 5), 16);
	const b1 = parseInt(hex1.slice(5, 7), 16);
	const r2 = parseInt(hex2.slice(1, 3), 16);
	const g2 = parseInt(hex2.slice(3, 5), 16);
	const b2 = parseInt(hex2.slice(5, 7), 16);

	const r = Math.round(r1 + (r2 - r1) * (1 - t));
	const g = Math.round(g1 + (g2 - g1) * (1 - t));
	const b = Math.round(b1 + (b2 - b1) * (1 - t));

	return toHex(r, g, b);
}

// ============================================
// REVEAL RESULT
// ============================================

function revealResult(mixedHex, cssCode, c1, c2) {
	// Animate the result section
	dom.resultSection.classList.add("result--revealed");
	setTimeout(() => dom.resultSection.classList.remove("result--revealed"), 1000);

	// Fill cocktail glass
	dom.resultLiquid.style.backgroundColor = mixedHex;
	dom.resultLiquid.classList.add("cocktail-glass__liquid--filled");

	// Add bubbles
	spawnBubbles(mixedHex);

	// Show garnish
	dom.garnish.textContent =
		GARNISHES[Math.floor(Math.random() * GARNISHES.length)];
	dom.garnish.classList.add("cocktail-glass__garnish--visible");

	// Update swatch and info
	dom.resultSwatch.style.backgroundColor = mixedHex;
	dom.resultSwatch.style.boxShadow = `0 4px 25px ${mixedHex}60`;
	dom.resultHex.textContent = mixedHex;
	dom.resultCode.textContent = cssCode;

	// Gradient preview
	const gradientCSS = `linear-gradient(90deg, ${c1}, ${mixedHex}, ${c2})`;
	dom.resultGradient.style.background = gradientCSS;
	dom.gradientCode.textContent = gradientCSS;
	dom.gradientWrap.classList.add("result__gradient-wrap--visible");

	// Scroll to result
	dom.resultSection.scrollIntoView({ behavior: "smooth", block: "center" });
}

function spawnBubbles(color) {
	dom.resultBubbles.innerHTML = "";
	for (let i = 0; i < 8; i++) {
		const b = document.createElement("div");
		b.className = "bubble";
		const size = 3 + Math.random() * 6;
		b.style.width = `${size}px`;
		b.style.height = `${size}px`;
		b.style.left = `${20 + Math.random() * 60}%`;
		b.style.bottom = `${Math.random() * 30}%`;
		b.style.animationDuration = `${1.5 + Math.random() * 2}s`;
		b.style.animationDelay = `${Math.random() * 2}s`;
		dom.resultBubbles.appendChild(b);
	}
}

// ============================================
// COPY TO CLIPBOARD
// ============================================

dom.copyBtn.addEventListener("click", () => {
	const code = dom.resultCode.textContent;
	if (!code || code.includes("Mix two colors")) return;

	navigator.clipboard
		.writeText(code)
		.then(() => {
			dom.copiedToast.classList.add("result__copied--show");
			setTimeout(
				() => dom.copiedToast.classList.remove("result__copied--show"),
				1500
			);
		})
		.catch(() => {
			// Fallback
			const ta = document.createElement("textarea");
			ta.value = code;
			document.body.appendChild(ta);
			ta.select();
			document.execCommand("copy");
			document.body.removeChild(ta);
			dom.copiedToast.classList.add("result__copied--show");
			setTimeout(
				() => dom.copiedToast.classList.remove("result__copied--show"),
				1500
			);
		});
});

// ============================================
// GALLERY
// ============================================

function addToGallery(hex, cssCode) {
	// Don't exceed 20 items
	if (state.recentMixes.length >= 20) {
		state.recentMixes.pop();
		const last = dom.galleryGrid.lastElementChild;
		if (last) last.remove();
	}

	state.recentMixes.unshift({ hex, cssCode });

	const item = document.createElement("div");
	item.className = "gallery__item";
	item.style.backgroundColor = hex;
	item.title = cssCode;

	item.innerHTML = `<div class="gallery__item-label">${hex}</div>`;

	item.addEventListener("click", () => {
		navigator.clipboard.writeText(cssCode).catch(() => {});
		item.querySelector(".gallery__item-label").textContent = "Copied!";
		setTimeout(() => {
			item.querySelector(".gallery__item-label").textContent = hex;
		}, 1000);
	});

	dom.galleryGrid.insertBefore(item, dom.galleryGrid.firstChild);
}

// ============================================
// UTILITIES
// ============================================

function delay(ms) {
	return new Promise((resolve) => setTimeout(resolve, ms));
}

// ============================================
// INIT
// ============================================

function init() {
	renderBottles();
	highlightActiveSlot();

	// Pre-select two default colors for a nice demo
	setTimeout(() => {
		const bottles = $$(".bottle");
		if (bottles.length >= 2) {
			pourBottle(BOTTLES[0].color, BOTTLES[0].name, bottles[0]);
			setTimeout(() => {
				pourBottle(BOTTLES[3].color, BOTTLES[3].name, bottles[3]);
			}, 300);
		}
	}, 500);
}

// --- Start ---
document.addEventListener("DOMContentLoaded", init);

style.css:
/* --- Reset & Base --- */
*,
*::before,
*::after {
	margin: 0;
	padding: 0;
	box-sizing: border-box;
}

:root {
	/* NES-inspired color palette */
	--bg-dark: #0f0f23;
	--bg-surface: #1a1a2e;
	--bg-panel: #16213e;
	--border-pixel: #3a3a5c;
	--border-light: #5a5a8c;
	--text-primary: #e8e8f0;
	--text-secondary: #a0a0c0;
	--text-muted: #606080;
	--nes-red: #e74040;
	--nes-orange: #f0a030;
	--nes-yellow: #f8f858;
	--nes-green: #58d854;
	--nes-cyan: #58f8f8;
	--nes-blue: #4878f8;
	--nes-purple: #a878f8;
	--nes-pink: #f878f8;
	--nes-white: #f8f8f8;
	--nes-black: #080820;

	--font-pixel: "Press Start 2P", monospace;
	--pixel: 4px;
	/* base pixel size for borders */
	--transition-fast: 0.15s steps(3);
	--transition-smooth: 0.3s steps(5);
}

html {
	scroll-behavior: smooth;
	image-rendering: pixelated;
}

body {
	font-family: var(--font-pixel);
	background: var(--bg-dark);
	color: var(--text-primary);
	min-height: 100vh;
	overflow-x: hidden;
	line-height: 1.8;
	font-size: 10px;
	/* Scanline effect */
	background-image: repeating-linear-gradient(
		0deg,
		transparent,
		transparent 2px,
		rgba(0, 0, 0, 0.15) 2px,
		rgba(0, 0, 0, 0.15) 4px
	);
	background-attachment: fixed;
}

/* ===== PIXEL BORDER UTILITY =====
   Uses box-shadow to create stepped pixel borders like NES/SNES UI
*/
.pixel-border {
	box-shadow:
        /* outer border */ var(--pixel) 0 0 0 var(--border-pixel),
		calc(var(--pixel) * -1) 0 0 0 var(--border-pixel),
		0 var(--pixel) 0 0 var(--border-pixel),
		0 calc(var(--pixel) * -1) 0 0 var(--border-pixel),
		/* corners */ var(--pixel) var(--pixel) 0 0 var(--border-pixel),
		calc(var(--pixel) * -1) var(--pixel) 0 0 var(--border-pixel),
		var(--pixel) calc(var(--pixel) * -1) 0 0 var(--border-pixel),
		calc(var(--pixel) * -1) calc(var(--pixel) * -1) 0 0 var(--border-pixel);
}

/* --- Ambient Background (pixel stars) --- */
.ambient-bg {
	position: fixed;
	inset: 0;
	z-index: 0;
	pointer-events: none;
	overflow: hidden;
}

.ambient-orb {
	position: absolute;
	border-radius: 0;
	/* No rounded anything in pixel art! */
	width: 6px;
	height: 6px;
	opacity: 0.6;
	animation: pixelTwinkle 2s steps(2) infinite;
}

.ambient-orb--1 {
	background: var(--nes-yellow);
	top: 10%;
	left: 15%;
	animation-delay: 0s;
}

.ambient-orb--2 {
	background: var(--nes-cyan);
	top: 30%;
	right: 20%;
	animation-delay: -0.7s;
}

.ambient-orb--3 {
	background: var(--nes-pink);
	bottom: 25%;
	left: 40%;
	animation-delay: -1.4s;
}

@keyframes pixelTwinkle {
	0%,
	100% {
		opacity: 0.3;
		transform: scale(1);
	}

	50% {
		opacity: 1;
		transform: scale(1.5);
	}
}

/* --- Header --- */
.header {
	position: relative;
	z-index: 1;
	text-align: center;
	padding: 2.5rem 1rem 1.5rem;
}

.header__icon {
	font-size: 2rem;
	margin-bottom: 0.75rem;
	animation: iconBounce 1s steps(4) infinite;
	display: inline-block;
}

@keyframes iconBounce {
	0%,
	100% {
		transform: translateY(0);
	}

	50% {
		transform: translateY(-8px);
	}
}

.header__title {
	line-height: 1.4;
	margin-bottom: 1rem;
}

.header__title-line1 {
	display: block;
	font-size: clamp(1rem, 4vw, 1.6rem);
	color: var(--nes-cyan);
	text-shadow: 3px 3px 0 var(--nes-blue), -1px -1px 0 rgba(0, 0, 0, 0.5);
	letter-spacing: 0.1em;
}

.header__title-line2 {
	display: block;
	font-size: clamp(1.2rem, 5vw, 2.2rem);
	color: var(--nes-yellow);
	text-shadow: 3px 3px 0 var(--nes-orange), -1px -1px 0 rgba(0, 0, 0, 0.5);
	letter-spacing: 0.05em;
	margin-top: 0.5rem;
}

.header__subtitle {
	font-size: 0.55rem;
	color: var(--text-secondary);
	line-height: 2;
}

.header__subtitle code {
	background: var(--bg-panel);
	border: 2px solid var(--border-pixel);
	padding: 0.2em 0.5em;
	color: var(--nes-green);
	font-family: var(--font-pixel);
	font-size: 0.55rem;
}

/* --- Station (Main Layout) --- */
.station {
	position: relative;
	z-index: 1;
	max-width: 1000px;
	margin: 0 auto;
	padding: 0 1rem 2rem;
	display: flex;
	flex-direction: column;
	gap: 2rem;
}

/* --- Panel Base Style (NES dialog box) --- */
.shelf,
.mixer,
.result,
.gallery {
	background: var(--bg-panel);
	border: 4px solid var(--border-light);
	outline: 4px solid var(--bg-dark);
	padding: 1.5rem;
	position: relative;
}

/* Inner pixel highlight on panels */
.shelf::before,
.mixer::before,
.result::before,
.gallery::before {
	content: "";
	position: absolute;
	top: 4px;
	left: 4px;
	right: 4px;
	bottom: 4px;
	border: 2px solid rgba(255, 255, 255, 0.06);
	pointer-events: none;
}

/* --- Shelf (Bottles) --- */
.shelf__title,
.gallery__title,
.result__title {
	font-family: var(--font-pixel);
	font-size: 0.65rem;
	color: var(--nes-yellow);
	margin-bottom: 1rem;
	text-align: center;
	text-shadow: 2px 2px 0 rgba(0, 0, 0, 0.5);
	text-transform: uppercase;
	letter-spacing: 0.1em;
}

.shelf__bottles {
	display: flex;
	flex-wrap: wrap;
	justify-content: center;
	gap: 0.6rem;
}

/* --- Bottle (Pixel Art Style) --- */
.bottle {
	--bottle-color: #ff6b6b;
	position: relative;
	width: 52px;
	cursor: pointer;
	transition: transform var(--transition-fast);
	display: flex;
	flex-direction: column;
	align-items: center;
	gap: 2px;
}

.bottle:hover {
	transform: translateY(-6px);
}

.bottle:active {
	transform: translateY(-2px);
}

.bottle.bottle--selected {
	transform: translateY(-10px);
}

.bottle__cap {
	width: 12px;
	height: 8px;
	background: #c0c0c0;
	border: 2px solid #808080;
	position: relative;
	z-index: 2;
}

.bottle__neck {
	width: 10px;
	height: 10px;
	background: rgba(255, 255, 255, 0.1);
	border: 2px solid var(--border-pixel);
}

.bottle__body {
	width: 36px;
	height: 48px;
	background: var(--bg-surface);
	border: 3px solid var(--border-pixel);
	position: relative;
	overflow: hidden;
}

.bottle__liquid {
	position: absolute;
	bottom: 0;
	left: 0;
	right: 0;
	height: 78%;
	background: var(--bottle-color);
}

/* Pixel shine: just a solid rectangle */
.bottle__liquid::after {
	content: "";
	position: absolute;
	top: 2px;
	left: 2px;
	width: 6px;
	height: 6px;
	background: rgba(255, 255, 255, 0.35);
}

.bottle__shine {
	position: absolute;
	top: 3px;
	left: 3px;
	width: 4px;
	height: 50%;
	background: rgba(255, 255, 255, 0.15);
	pointer-events: none;
}

.bottle__label {
	font-size: 0.4rem;
	color: var(--text-muted);
	text-align: center;
	max-width: 52px;
	overflow: hidden;
	text-overflow: ellipsis;
	white-space: nowrap;
	transition: color var(--transition-fast);
	font-family: var(--font-pixel);
}

.bottle:hover .bottle__label {
	color: var(--nes-white);
}

.bottle--selected .bottle__label {
	color: var(--nes-cyan);
}

/* Pixel glow — small colored square under bottle */
.bottle__glow {
	position: absolute;
	bottom: -4px;
	left: 50%;
	transform: translateX(-50%);
	width: 20px;
	height: 4px;
	opacity: 0;
	transition: opacity var(--transition-fast);
	pointer-events: none;
	background: var(--bottle-color);
}

.bottle:hover .bottle__glow,
.bottle--selected .bottle__glow {
	opacity: 0.6;
}

/* --- Mixer Section --- */
.mixer {
	display: flex;
	flex-direction: column;
	align-items: center;
	gap: 1.5rem;
}

.mixer__slots {
	display: flex;
	align-items: center;
	gap: 1rem;
	width: 100%;
	justify-content: center;
	flex-wrap: wrap;
}

/* --- Pour Slot --- */
.pour-slot {
	display: flex;
	flex-direction: column;
	align-items: center;
	gap: 0.4rem;
	min-width: 110px;
}

.pour-slot__label {
	font-size: 0.5rem;
	color: var(--nes-orange);
	text-transform: uppercase;
	letter-spacing: 0.1em;
	text-shadow: 1px 1px 0 rgba(0, 0, 0, 0.5);
}

.pour-slot__glass {
	width: 80px;
	height: 80px;
	border: 3px solid var(--border-pixel);
	display: flex;
	align-items: center;
	justify-content: center;
	position: relative;
	overflow: hidden;
	cursor: pointer;
	background: var(--bg-surface);
	transition: border-color var(--transition-fast);
}

.pour-slot__glass:hover {
	border-color: var(--nes-cyan);
}

.pour-slot__glass.pour-slot__glass--filled {
	border-color: var(--border-light);
}

.pour-slot__liquid {
	position: absolute;
	inset: 0;
	opacity: 0;
	transition: opacity 0.3s steps(4);
}

.pour-slot__liquid.pour-slot__liquid--visible {
	opacity: 1;
}

.pour-slot__empty {
	font-size: 0.4rem;
	color: var(--text-muted);
	text-align: center;
	pointer-events: none;
	transition: opacity var(--transition-fast);
	line-height: 1.6;
}

.pour-slot__glass--filled .pour-slot__empty {
	opacity: 0;
}

.pour-slot__color-name {
	font-size: 0.45rem;
	color: var(--text-secondary);
	font-family: var(--font-pixel);
}

.pour-slot__picker {
	width: 32px;
	height: 24px;
	border: 2px solid var(--border-pixel);
	cursor: pointer;
	background: var(--bg-surface);
	padding: 0;
}

.pour-slot__picker::-webkit-color-swatch-wrapper {
	padding: 2px;
}

.pour-slot__picker::-webkit-color-swatch {
	border: none;
}

/* --- Proportion Slider --- */
.mixer__proportion {
	display: flex;
	flex-direction: column;
	align-items: center;
	gap: 0.4rem;
	min-width: 140px;
}

.proportion__display {
	display: flex;
	align-items: center;
	gap: 0.5rem;
}

.proportion__val {
	min-width: 42px;
	text-align: center;
	font-size: 0.6rem;
}

.proportion__val--left {
	color: var(--nes-red);
}

.proportion__val--right {
	color: var(--nes-cyan);
}

.proportion__divider {
	font-size: 1rem;
	animation: iconBounce 1.5s steps(4) infinite;
}

.proportion__slider {
	width: 100%;
	-webkit-appearance: none;
	appearance: none;
	height: 8px;
	background: var(--bg-surface);
	border: 2px solid var(--border-pixel);
	outline: none;
	cursor: pointer;
}

.proportion__slider::-webkit-slider-thumb {
	-webkit-appearance: none;
	width: 16px;
	height: 20px;
	background: var(--nes-white);
	border: 2px solid var(--border-pixel);
	cursor: pointer;
}

.proportion__slider::-webkit-slider-thumb:hover {
	background: var(--nes-yellow);
}

.proportion__labels {
	display: flex;
	justify-content: space-between;
	width: 100%;
	font-size: 0.4rem;
	color: var(--text-muted);
}

/* --- Color Space Selector --- */
.mixer__colorspace {
	display: flex;
	flex-direction: column;
	align-items: center;
	gap: 0.5rem;
	width: 100%;
}

.colorspace__label {
	font-size: 0.5rem;
	color: var(--nes-orange);
	text-transform: uppercase;
	letter-spacing: 0.1em;
	text-shadow: 1px 1px 0 rgba(0, 0, 0, 0.5);
}

.colorspace__options {
	display: flex;
	flex-wrap: wrap;
	gap: 0.4rem;
	justify-content: center;
}

.colorspace__btn {
	padding: 0.4em 0.8em;
	border: 2px solid var(--border-pixel);
	background: var(--bg-surface);
	color: var(--text-secondary);
	font-size: 0.45rem;
	font-family: var(--font-pixel);
	cursor: pointer;
	transition: var(--transition-fast);
}

.colorspace__btn:hover {
	border-color: var(--nes-cyan);
	color: var(--nes-white);
	background: var(--bg-panel);
}

.colorspace__btn--active {
	border-color: var(--nes-cyan);
	background: var(--nes-blue);
	color: var(--nes-white);
}

/* --- Mix Button (NES START Button style) --- */
.mixer__btn {
	position: relative;
	padding: 0.8em 2em;
	border: 4px solid var(--nes-white);
	background: var(--nes-red);
	color: var(--nes-white);
	font-size: 0.7rem;
	font-family: var(--font-pixel);
	cursor: pointer;
	text-transform: uppercase;
	letter-spacing: 0.1em;
	text-shadow: 2px 2px 0 rgba(0, 0, 0, 0.4);
	transition: var(--transition-fast);
	box-shadow: 4px 4px 0 0 rgba(0, 0, 0, 0.4);
	animation: btnPulse 2s steps(2) infinite;
}

@keyframes btnPulse {
	0%,
	100% {
		border-color: var(--nes-white);
	}

	50% {
		border-color: var(--nes-yellow);
	}
}

.mixer__btn:hover {
	background: var(--nes-orange);
	transform: translate(0, -2px);
	box-shadow: 4px 6px 0 0 rgba(0, 0, 0, 0.4);
}

.mixer__btn:active {
	transform: translate(2px, 2px);
	box-shadow: 2px 2px 0 0 rgba(0, 0, 0, 0.4);
}

/* Hide the old shine effect */
.mixer__btn-shine {
	display: none;
}

/* --- Result Section --- */
.result {
	display: flex;
	flex-direction: column;
	align-items: center;
	gap: 1.2rem;
}

/* --- Cocktail Glass (Pixel Art Style) --- */
.result__glass-wrap {
	position: relative;
	display: flex;
	flex-direction: column;
	align-items: center;
	padding-top: 0.5rem;
}

.cocktail-glass {
	width: 120px;
	height: 90px;
	position: relative;
	overflow: hidden;
	/* Pixel art trapezoid using clip-path with steps */
	clip-path: polygon(
		8% 0%,
		92% 0%,
		88% 10%,
		12% 10%,
		84% 20%,
		16% 20%,
		80% 30%,
		20% 30%,
		76% 40%,
		24% 40%,
		72% 50%,
		28% 50%,
		68% 60%,
		32% 60%,
		64% 70%,
		36% 70%,
		60% 80%,
		40% 80%,
		56% 90%,
		44% 90%,
		52% 100%,
		48% 100%
	);
	background: var(--bg-surface);
	border: 3px solid var(--border-pixel);
}

.cocktail-glass__liquid {
	position: absolute;
	bottom: 0;
	left: 0;
	right: 0;
	height: 0%;
	transition: height 0.8s steps(8), background-color 0.3s steps(4);
}

.cocktail-glass__liquid.cocktail-glass__liquid--filled {
	height: 85%;
}

.cocktail-glass__reflection {
	position: absolute;
	top: 6px;
	left: 25%;
	width: 6px;
	height: 6px;
	background: rgba(255, 255, 255, 0.25);
	pointer-events: none;
}

.cocktail-glass__bubbles {
	position: absolute;
	inset: 0;
	pointer-events: none;
}

/* Pixel bubbles */
.bubble {
	position: absolute;
	border-radius: 0;
	/* Square pixels! */
	background: rgba(255, 255, 255, 0.3);
	animation: bubbleRise 2.5s steps(10) infinite;
}

@keyframes bubbleRise {
	0% {
		transform: translateY(0);
		opacity: 0.6;
	}

	100% {
		transform: translateY(-80px);
		opacity: 0;
	}
}

.cocktail-glass__stem {
	width: 6px;
	height: 40px;
	background: var(--border-pixel);
	margin: 0 auto;
}

.cocktail-glass__base {
	width: 50px;
	height: 8px;
	background: var(--border-pixel);
	margin: 0 auto;
}

.cocktail-glass__garnish {
	position: absolute;
	top: -8px;
	right: 8px;
	font-size: 1.4rem;
	transform: rotate(15deg);
	opacity: 0;
	transition: opacity var(--transition-fast);
	/* Pixelated emoji */
	image-rendering: pixelated;
}

.cocktail-glass__garnish.cocktail-glass__garnish--visible {
	opacity: 1;
	animation: garnishBounce 0.5s steps(4);
}

@keyframes garnishBounce {
	0% {
		transform: rotate(15deg) translateY(-12px);
		opacity: 0;
	}

	100% {
		transform: rotate(15deg) translateY(0);
		opacity: 1;
	}
}

/* --- Result Info --- */
.result__info {
	display: flex;
	align-items: center;
	gap: 0.75rem;
	width: 100%;
	max-width: 500px;
}

.result__swatch {
	width: 48px;
	height: 48px;
	border: 3px solid var(--border-light);
	flex-shrink: 0;
	transition: background-color 0.3s steps(4);
}

.result__details {
	flex: 1;
	display: flex;
	flex-direction: column;
	gap: 0.3rem;
	position: relative;
}

.result__hex {
	font-size: 0.7rem;
	color: var(--nes-white);
	text-shadow: 2px 2px 0 rgba(0, 0, 0, 0.3);
}

.result__code-wrap {
	display: flex;
	align-items: center;
	gap: 0.4rem;
}

.result__code {
	font-size: 0.4rem;
	color: var(--nes-green);
	background: var(--nes-black);
	padding: 0.4em 0.6em;
	border: 2px solid var(--border-pixel);
	flex: 1;
	overflow-x: auto;
	white-space: nowrap;
	font-family: var(--font-pixel);
	line-height: 1.8;
}

.result__copy {
	background: var(--bg-surface);
	border: 2px solid var(--border-pixel);
	color: var(--text-secondary);
	padding: 0.3em 0.5em;
	cursor: pointer;
	font-size: 0.7rem;
	transition: var(--transition-fast);
	flex-shrink: 0;
}

.result__copy:hover {
	background: var(--nes-blue);
	border-color: var(--nes-cyan);
	color: var(--nes-white);
}

.result__copied {
	position: absolute;
	bottom: -20px;
	right: 0;
	font-size: 0.4rem;
	color: var(--nes-green);
	opacity: 0;
	transition: opacity var(--transition-fast);
	pointer-events: none;
	text-shadow: 1px 1px 0 rgba(0, 0, 0, 0.5);
}

.result__copied.result__copied--show {
	opacity: 1;
}

/* --- Gradient Preview --- */
.result__gradient-wrap {
	width: 100%;
	max-width: 500px;
	display: flex;
	flex-direction: column;
	gap: 0.4rem;
	opacity: 0;
	transition: opacity 0.3s steps(4);
}

.result__gradient-wrap.result__gradient-wrap--visible {
	opacity: 1;
}

.result__gradient-label {
	font-size: 0.45rem;
	color: var(--nes-orange);
	text-transform: uppercase;
	letter-spacing: 0.1em;
	text-shadow: 1px 1px 0 rgba(0, 0, 0, 0.5);
}

.result__gradient {
	height: 32px;
	border: 3px solid var(--border-pixel);
	/* Pixelate the gradient! */
	image-rendering: pixelated;
}

.result__gradient-code {
	font-size: 0.35rem;
	color: var(--text-muted);
	word-break: break-all;
	font-family: var(--font-pixel);
	line-height: 1.8;
}

/* --- Gallery --- */
.gallery__grid {
	display: grid;
	grid-template-columns: repeat(auto-fill, minmax(60px, 1fr));
	gap: 0.5rem;
}

.gallery__item {
	aspect-ratio: 1;
	border: 3px solid var(--border-pixel);
	position: relative;
	overflow: hidden;
	cursor: pointer;
	transition: transform var(--transition-fast);
	animation: galleryPopIn 0.3s steps(4);
}

@keyframes galleryPopIn {
	from {
		transform: scale(0);
	}

	to {
		transform: scale(1);
	}
}

.gallery__item:hover {
	transform: scale(1.15);
	border-color: var(--nes-yellow);
	z-index: 2;
}

.gallery__item-label {
	position: absolute;
	bottom: 0;
	left: 0;
	right: 0;
	padding: 0.2em;
	font-size: 0.35rem;
	text-align: center;
	background: rgba(0, 0, 0, 0.7);
	color: var(--nes-white);
	font-family: var(--font-pixel);
	opacity: 0;
	transition: opacity var(--transition-fast);
}

.gallery__item:hover .gallery__item-label {
	opacity: 1;
}

/* --- Shaker Overlay --- */
.shaker-overlay {
	position: fixed;
	inset: 0;
	z-index: 100;
	background: rgba(8, 8, 32, 0.92);
	display: flex;
	flex-direction: column;
	align-items: center;
	justify-content: center;
	opacity: 0;
	pointer-events: none;
	transition: opacity 0.2s steps(3);
}

.shaker-overlay.shaker-overlay--active {
	opacity: 1;
	pointer-events: auto;
}

.shaker {
	position: relative;
	width: 70px;
	display: flex;
	flex-direction: column;
	align-items: center;
}

.shaker__top {
	width: 32px;
	height: 24px;
	background: #a0a0a0;
	border: 3px solid #707070;
	position: relative;
	z-index: 2;
}

.shaker__body {
	width: 56px;
	height: 90px;
	background: var(--bg-surface);
	border: 3px solid var(--border-light);
	position: relative;
	overflow: hidden;
}

.shaker__liquid {
	position: absolute;
	bottom: 0;
	left: 0;
	right: 0;
	height: 60%;
	transition: background-color 0.3s steps(4);
}

.shaker__shine {
	position: absolute;
	top: 10px;
	left: 6px;
	width: 6px;
	height: 60px;
	background: rgba(255, 255, 255, 0.1);
	pointer-events: none;
}

.shaker__particles {
	position: absolute;
	inset: 0;
	pointer-events: none;
}

/* Pixel particles — square! */
.shaker-particle {
	position: absolute;
	border-radius: 0;
	animation: shakerParticle 1s steps(8) forwards;
}

@keyframes shakerParticle {
	0% {
		transform: translate(0, 0);
		opacity: 1;
	}

	100% {
		transform: translate(var(--tx), var(--ty));
		opacity: 0;
	}
}

.shaker-overlay--active .shaker {
	animation: shakerShake 0.35s steps(4) 3;
}

@keyframes shakerShake {
	0%,
	100% {
		transform: rotate(0deg) translateY(0);
	}

	25% {
		transform: rotate(-12deg) translateY(-8px);
	}

	75% {
		transform: rotate(12deg) translateY(-8px);
	}
}

/* --- Pour Animation --- */
.pour-slot__glass.pour-slot__glass--pouring {
	animation: pourFlash 0.4s steps(2);
}

@keyframes pourFlash {
	0%,
	100% {
		border-color: var(--border-pixel);
	}

	50% {
		border-color: var(--nes-yellow);
	}
}

/* --- Result reveal --- */
.result.result--revealed .cocktail-glass {
	animation: glassAppear 0.5s steps(5);
}

@keyframes glassAppear {
	0% {
		transform: scale(0.5);
		opacity: 0;
	}

	100% {
		transform: scale(1);
		opacity: 1;
	}
}

/* --- Footer --- */
.footer {
	position: relative;
	z-index: 1;
	text-align: center;
	padding: 1.5rem;
	color: var(--text-muted);
	font-size: 0.45rem;
}

.footer strong {
	color: var(--nes-purple);
}

/* --- Responsive --- */
@media (max-width: 640px) {
	.mixer__slots {
		flex-direction: column;
	}

	.mixer__proportion {
		order: 3;
		flex-direction: row;
		flex-wrap: wrap;
		justify-content: center;
	}

	.proportion__slider {
		max-width: 180px;
	}

	.result__info {
		flex-direction: column;
		text-align: center;
	}

	.cocktail-glass {
		width: 90px;
		height: 70px;
	}

	.bottle {
		width: 44px;
	}

	.bottle__body {
		width: 30px;
		height: 40px;
	}

	.gallery__grid {
		grid-template-columns: repeat(auto-fill, minmax(48px, 1fr));
	}
}

/* --- no-select --- */
.no-select {
	user-select: none;
	-webkit-user-select: none;
}

/* --- Scrollbar (pixel style) --- */
::-webkit-scrollbar {
	width: 8px;
	height: 8px;
}

::-webkit-scrollbar-track {
	background: var(--bg-dark);
}

::-webkit-scrollbar-thumb {
	background: var(--border-pixel);
}

::-webkit-scrollbar-thumb:hover {
	background: var(--border-light);
}

/* --- Extra: blinking cursor for retro feel --- */
@keyframes blink {
	0%,
	100% {
		opacity: 1;
	}

	50% {
		opacity: 0;
	}
}
